func quoteCustomerSmartPickerVM(vm QuoteDetailVM) ui.SmartPickerVM {
	return ui.SmartPickerVM{
		Label:         "",
		FieldName:     "customer_id",
		Entity:        "customer",
		Context:       "quote.customer_picker",
		Value:         quoteCustomerIDValue(vm),
		SelectedLabel: quoteCustomerSelectedLabel(vm),
		Placeholder:   "Search customers...",
		Required:      true,
		Limit:         20,
	}
}

func quoteCustomerIDValue(vm QuoteDetailVM) string {
	if vm.Quote.CustomerID == 0 {
		return ""
	}
	return Uitoa(vm.Quote.CustomerID)
}

func quoteCustomerSelectedLabel(vm QuoteDetailVM) string {
	if vm.Quote.CustomerID == 0 {
		return ""
	}
	if vm.Quote.Customer.Name != "" {
		return vm.Quote.Customer.Name
	}
	for _, c := range vm.Customers {
		if c.ID == vm.Quote.CustomerID {
			return c.Name
		}
	}
	return ""
}

